// Pattern-matching switch (like Kotlin's when / Rust's match)
sealed class Shape {}
class Circle extends Shape { Circle(this.r); final double r; }
class Square extends Shape { Square(this.s); final double s; }

double area(Shape sh) => switch (sh) {
  Circle(:final r) => 3.14 * r * r,      // destructure Circle's r
  Square(:final s) => s * s,
  // No default — the compiler proves we handled every case in the sealed hierarchy.
};

