// Future = one value later. async/await reads sequential, runs non-blocking.
Future<User> fetchUser(int id) async {
  final resp = await http.get(Uri.parse('/users/$id'));
  return User.fromJson(jsonDecode(resp.body));
}

// Stream = many values over time. Same async/await via for-loop.
Stream<int> tick() async* {
  for (var i = 0; ; i++) { yield i; await Future.delayed(Duration(seconds: 1)); }
}

await for (final n in tick().take(5)) { print(n); }

