// File: bin/user_app.dart
// Run: dart run bin/user_app.dart

import 'dart:convert';

sealed class Result<T> {
  const Result();
}
class Ok<T>   extends Result<T> { const Ok(this.value); final T value; }
class Err<T>  extends Result<T> { const Err(this.error); final Object error; }

class User {
  User({required this.id, required this.name, this.email});
  final int id;
  final String name;
  final String? email;

  factory User.fromJson(Map<String, dynamic> j) => User(
    id: j['id'] as int,
    name: j['name'] as String,
    email: j['email'] as String?,
  );

  @override
  String toString() => 'User($id, $name, ${email ?? '(no email)'})';
}

Result<List<User>> parseUsers(String jsonStr) {
  try {
    final list = (jsonDecode(jsonStr) as List).cast<Map<String, dynamic>>();
    return Ok(list.map(User.fromJson).toList());
  } catch (e) {
    return Err(e);
  }
}

void main() {
  const json = '''[{"id":1,"name":"Ada"},{"id":2,"name":"Ben","email":"b@x.com"}]''';
  final result = parseUsers(json);

  // Pattern matching over the sealed Result — exhaustive, no default needed.
  switch (result) {
    case Ok(:final value):
      for (final u in value) print(u);
    case Err(:final error):
      print('parse failed: $error');
  }
}

// Output:
//   User(1, Ada, (no email))
//   User(2, Ben, b@x.com)
